/**
 * Runs student-created "tool" scripts on behalf of a language model, as part
 * of the ML4K prompt-with-tools support.
 *
 * Tools are scripts in the invoking sprite's workspace, created with the
 * "Make a Tool" UI: an mlforkidstools_definition hat with an
 * mlforkidstools_prototype block whose mutation carries everything an OpenAI
 * function-calling schema needs (tool code, description, parameter names /
 * ids / defaults / descriptions, and whether the body contains a
 * "report answer" block).
 */

const Thread = require('../../engine/thread');

/**
 * How often to check whether a running tool script has finished.
 * There is deliberately no timeout: like `broadcast and wait`, a tool script
 * is allowed to run for as long as it needs (student scripts can legitimately
 * contain `ask ... and wait` or `wait until` blocks, and school machines can
 * be slow). The stop button is the escape hatch, via the shouldAbort callback.
 */
const POLL_INTERVAL_MS = 50;

/**
 * Parse a JSON mutation attribute, returning a fallback on bad/missing data.
 * @param {?string} value - the raw mutation attribute value.
 * @param {*} fallback - value to use if the attribute is missing or invalid.
 * @returns {*} the parsed value, or the fallback.
 */
const parseMutationJson = function (value, fallback) {
    if (!value) {
        return fallback;
    }
    try {
        return JSON.parse(value);
    } catch (err) {
        return fallback;
    }
};

/**
 * @typedef {object} ToolInfo
 * @property {string} name - identifier the model uses to call the tool
 * @property {string} displayName - human-readable tool name, for messages shown to the student
 * @property {string} toolCode - the raw tool code from the workspace (with parameter placeholders)
 * @property {string} topBlockId - id of the definition block at the top of the tool's script
 * @property {Array.<string>} paramNames - parameter names, as used by argument reporter blocks
 * @property {boolean} hasReport - true if the tool's body contains a "report answer" block
 * @property {object} schema - OpenAI-style function-calling schema describing the tool
 */

/**
 * List the tools defined on a target.
 * @param {Target} target - the sprite whose workspace to scan.
 * @returns {Array.<ToolInfo>} the tools the model can be offered.
 */
const listTools = function (target) {
    const tools = [];
    const usedNames = {};

    target.blocks.getScripts().forEach(topBlockId => {
        const definition = target.blocks.getBlock(topBlockId);
        if (!definition || definition.opcode !== 'mlforkidstools_definition') {
            return;
        }
        const prototypeInput = definition.inputs && definition.inputs.custom_block;
        const prototype = prototypeInput && target.blocks.getBlock(prototypeInput.block);
        if (!prototype || !prototype.mutation || !prototype.mutation.toolcode) {
            return;
        }
        const mutation = prototype.mutation;

        // toolcode is the tool name with parameter placeholders, e.g. "move sprite %s"
        const displayName = mutation.toolcode
            .replace(/%[snb]/g, ' ')
            .replace(/\s+/g, ' ')
            .trim();
        if (!displayName) {
            return;
        }

        const paramNames = parseMutationJson(mutation.argumentnames, []);
        const paramIds = parseMutationJson(mutation.argumentids, []);
        // per-parameter descriptions are keyed by argument id
        const paramDescriptions = parseMutationJson(mutation.argumentdescriptions, {});
        // placeholder order in the toolcode gives each parameter's type
        const placeholders = mutation.toolcode.match(/%[snb]/g) || [];

        let name = displayName.toLowerCase()
            .replace(/[^a-z0-9]+/g, '_')
            .replace(/^_+|_+$/g, '');
        if (!name) {
            name = 'tool';
        }
        while (usedNames[name]) {
            name = `${name}_`;
        }
        usedNames[name] = true;

        const properties = {};
        paramNames.forEach((paramName, idx) => {
            properties[paramName] = {
                type: placeholders[idx] === '%b' ? 'boolean' : 'string',
                description: paramDescriptions[paramIds[idx]] || paramName
            };
        });

        tools.push({
            name,
            displayName,
            toolCode: mutation.toolcode,
            topBlockId,
            paramNames,
            hasReport: parseMutationJson(mutation.hasreport, false) === true,
            schema: {
                type: 'function',
                function: {
                    name,
                    description: mutation.description || displayName,
                    parameters: {
                        type: 'object',
                        properties,
                        // there is (currently) no way for students to mark a
                        //  parameter as optional in the Make a Tool UI, so
                        //  every parameter is described as required
                        required: paramNames.slice()
                    }
                }
            }
        });
    });

    return tools;
};

/**
 * @typedef {object} ToolOutcome
 * @property {boolean} aborted - true if the project was stopped while the tool was running
 * @property {*} [answer] - the value the tool script reported, if it reported one
 */

/**
 * Run a tool script and wait for it to finish.
 *
 * The model's arguments are made readable by argument reporter blocks inside
 * the script the same way tool/procedure arguments are: params live on a
 * stack frame below the executing blocks. (Frames are reset on every block
 * advance, so params cannot live on the executing frame itself; and with no
 * mlforkidstools_call block to supply the caller frame, a bottom stack entry
 * of null is used - it is never executed, and when the script ends the thread
 * pops through it cleanly to done instead of re-running the body.)
 *
 * For a tool whose body contains a "report answer" block (hasReport), that
 * same bottom frame also carries the pending-report state that an in-thread
 * mlforkidstools_call would put on its caller frame (ml4kReportResolve /
 * ml4kReportReturnDepth), so the standard mlforkidstools_report primitive
 * delivers its value straight to this runner. A body that ends without
 * reporting resolves via Thread.popStack's fall-through default, which is
 * detected (ml4kReportFellThrough) and treated as "no answer" - a normal,
 * supported case (e.g. the report block is inside an if that wasn't taken).
 *
 * @param {Runtime} runtime - the VM runtime.
 * @param {Target} target - the sprite the tool script belongs to.
 * @param {ToolInfo} tool - the tool to run, as returned by listTools.
 * @param {object} args - argument values from the model, keyed by parameter name.
 * @param {Function} shouldAbort - returns true if the run should be treated as aborted
 *   (the stop button empties runtime.threads without marking threads, so completion
 *   alone cannot distinguish "finished" from "stopped").
 * @returns {Promise.<ToolOutcome>} resolves when the tool script has finished.
 */
const runToolScript = function (runtime, target, tool, args, shouldAbort) {
    const thread = runtime._pushThread(tool.topBlockId, target);

    thread.popStack();
    thread.pushStack(null);
    thread.initParams();
    Object.keys(args).forEach(paramName => {
        thread.pushParam(paramName, args[paramName]);
    });

    let reportPromise = null;
    if (tool.hasReport) {
        const bottomFrame = thread.peekStackFrame();
        reportPromise = new Promise(resolveReport => {
            bottomFrame.ml4kReportResolve = resolveReport;
            // unwind back to the bottom frame's own level when reporting
            bottomFrame.ml4kReportReturnDepth = 1;
            bottomFrame.ml4kReportToolCode = tool.toolCode;
            thread.ml4kReportWaitDepth++;
        });
    }

    thread.pushStack(tool.topBlockId);

    return new Promise(resolve => {
        let settled = false;
        let poll = null;
        const settle = outcome => {
            if (settled) {
                return;
            }
            settled = true;
            clearInterval(poll);
            resolve(outcome);
        };

        if (reportPromise) {
            reportPromise.then(value => {
                const fellThrough = thread.ml4kReportFellThrough;
                // the report left the thread parked in STATUS_PROMISE_WAIT
                //  with no in-thread caller to resume it - retire it so the
                //  sequencer clears it away on its next pass
                thread.status = Thread.STATUS_DONE;
                if (shouldAbort && shouldAbort()) {
                    return settle({aborted: true});
                }
                if (fellThrough) {
                    // the body ended without reporting - no answer
                    return settle({aborted: false});
                }
                settle({aborted: false, answer: value});
            });
        }

        // completion / stop watch: a statement-shaped tool is finished when
        //  its thread leaves runtime.threads; a report-shaped tool reaching
        //  here without its report promise resolving was stopped externally
        poll = setInterval(() => {
            if (runtime.threads.indexOf(thread) !== -1) {
                return;
            }
            if (settled) {
                clearInterval(poll);
                return;
            }
            if ((shouldAbort && shouldAbort()) || tool.hasReport) {
                return settle({aborted: true});
            }
            settle({aborted: false});
        }, POLL_INTERVAL_MS);
    });
};

module.exports = {
    listTools,
    runToolScript
};
