const toolRunner = require('./tool-runner');

// upper bound on model<->tool round trips for a single prompt-with-tools request
const MAX_TOOL_ITERATIONS = 10;

// emitted on the runtime when the model in use supports function calling, to
// reveal the (hidden-by-default) "My Tools" support in the palette
//  (Runtime.ML4K_TOOLS_ENABLE_REQUEST - the runtime listens for this and
//   re-broadcasts ML4K_TOOLS_ENABLED to the GUI)
const TOOLS_SUPPORT_AVAILABLE_EVENT = 'ML4K_TOOLS_ENABLE_REQUEST';

class ML4KidsWebLlm {

    constructor (runtime) {
        this.MODELS = {};
        this.state = 'INIT';

        // needed for tools support: looking up the sprite that invoked a
        // prompt-with-tools block, and running that sprite's tool scripts
        this._runtime = runtime;
    }

    initModel (requestdata, worker) {
        console.log('[mlforkids] init model', requestdata);

        const modelid = requestdata.modelid;
        const contextwindow = requestdata.contextwindow;

        this.MODELS[modelid + '-' + contextwindow] = {
            state : 'INIT',
            busy  : false,
            messages : [],
            initialcontext : null
        };
        this._loadWebLlmProjectSupport()
            .then((webllmLib) => {
                this._enableToolsSupportForModel(webllmLib, modelid);
                this.MODELS[modelid + '-' + contextwindow].webllmEngine = new window.mlforkidsWebLlm.MLCEngine();
                const modelCfg = {
                    context_window_size : contextwindow
                };
                console.log('[mlforkids] loading model', modelid, modelCfg);
                return this.MODELS[modelid + '-' + contextwindow].webllmEngine.reload(modelid, modelCfg);
            })
            .then(() => {
                console.log('[mlforkids] loaded model');
                this.MODELS[modelid + '-' + contextwindow].state = 'READY';

                worker.postMessage({
                    mlforkidswebllm: 'modelready',
                    data: { modelid, contextwindow }
                });
            })
            .catch((err) => {
                console.log('[mlforkids] failed to load model', err);
                this.MODELS[modelid + '-' + contextwindow].state = 'ERROR';

                worker.postMessage({
                    mlforkidswebllm: 'modelfailed',
                    data: { modelid, contextwindow }
                });
            });

        // reset if the user clicks the Scratch stop button
        //  (registered once - the listener covers all models)
        if (!this._stopListenerRegistered) {
            this._stopListenerRegistered = true;
            window.addEventListener('mlforkids-runtime-project-stop-all', () => {
                Object.keys(this.MODELS).forEach((modelKey) => {
                    this.MODELS[modelKey].busy = false;

                    const messages = this.MODELS[modelKey].messages;
                    if (messages && messages.length > 2 && messages[messages.length - 1].role === 'user') {
                        messages.pop();
                    }
                });
            });
        }
    }

    clearContext (requestdata) {
        const modelid       = requestdata.modelid;
        const contextwindow = requestdata.contextwindow;
        const modelKey = modelid + '-' + contextwindow;
        if (modelKey in this.MODELS === false) {
            console.log('[mlforkids] Unknown model ' + modelKey);
            return;
        }
        this.MODELS[modelKey].messages = [];
        this.MODELS[modelKey].initialcontext = null;
    }

    initialContext (requestdata) {
        const modelid        = requestdata.modelid;
        const contextwindow  = requestdata.contextwindow;
        const modelKey = modelid + '-' + contextwindow;
        const initialcontext = requestdata.initialcontext;
        if (modelKey in this.MODELS === false) {
            console.log('[mlforkids] Unknown model ' + modelKey);
            return;
        }
        this.MODELS[modelKey].initialcontext = initialcontext;
    }

    promptModel (requestdata, worker) {
        console.log('[mlforkids] prompt model');

        const requestid     = requestdata.requestid;
        const modelid       = requestdata.modelid;
        const contextwindow = requestdata.contextwindow;
        const input         = requestdata.input;
        const temperature   = requestdata.temperature;
        const top_p         = requestdata.top_p;

        const modelKey = modelid + '-' + contextwindow;
        // every prompt request must get a promptresponse reply, otherwise the
        //  Scratch block waiting on it never resolves and the thread is stuck
        if (modelKey in this.MODELS === false) {
            console.log('[mlforkids] Unknown model ' + modelKey);
            this._replyToPrompt(requestid, modelid, contextwindow, 'Unable to respond', worker);
            return;
        }
        if (this.MODELS[modelKey].state !== 'READY') {
            console.log('[mlforkids] Model not ready');
            this._replyToPrompt(requestid, modelid, contextwindow, 'The model is not ready', worker);
            return;
        }
        if (this.MODELS[modelKey].busy) {
            console.log('[mlforkids] Model is busy');
            this._replyToPrompt(requestid, modelid, contextwindow, 'The model is busy', worker);
            return;
        }

        this.MODELS[modelKey].busy = true;

        this._submitPrompt (requestid, modelid, contextwindow, modelKey, temperature, top_p, input, worker);
    }


    promptModelWithTools (requestdata, worker) {
        console.log('[mlforkids] prompt model with tools');

        const requestid     = requestdata.requestid;
        const modelid       = requestdata.modelid;
        const contextwindow = requestdata.contextwindow;
        const input         = requestdata.input;
        const temperature   = requestdata.temperature;
        const top_p         = requestdata.top_p;
        const targetid      = requestdata.targetid;

        const modelKey = modelid + '-' + contextwindow;
        // every prompt request must get a promptresponse reply, otherwise the
        //  Scratch block waiting on it never resolves and the thread is stuck
        if (modelKey in this.MODELS === false) {
            console.log('[mlforkids] Unknown model ' + modelKey);
            this._replyToPrompt(requestid, modelid, contextwindow, 'Unable to respond', worker);
            return;
        }
        if (this.MODELS[modelKey].state !== 'READY') {
            console.log('[mlforkids] Model not ready');
            this._replyToPrompt(requestid, modelid, contextwindow, 'The model is not ready', worker);
            return;
        }
        if (this.MODELS[modelKey].busy) {
            console.log('[mlforkids] Model is busy');
            this._replyToPrompt(requestid, modelid, contextwindow, 'The model is busy', worker);
            return;
        }

        this.MODELS[modelKey].busy = true;

        this._submitPromptWithTools(requestid, modelid, contextwindow, modelKey,
            temperature, top_p, input, targetid, worker);
    }


    _replyToPrompt (requestid, modelid, contextwindow, response, worker) {
        worker.postMessage({
            mlforkidswebllm: 'promptresponse',
            data: { requestid, modelid, contextwindow, response }
        });
    }


    _systemPrompt (rag) {
        const systemPromptInsert = rag ?
                'You will be given additional context to help answer questions. ' +
                'Answer only using the provided context. '
                :
                '';

        return {
            role    : 'system',
            content : 'You are a friendly and supportive AI assistant for children. ' +
                      'Use simple, clear, and encouraging language. Keep responses short. ' +
                      'Avoid harmful, inappropriate, scary, or violent content. ' +
                      'Always be positive and constructive. Avoid sarcasm or harsh language. ' +
                      systemPromptInsert +
                      'Promote digital safety by reminding children not to share personal ' +
                      'information. Do not ask for personal information. If a child asks ' +
                      'something unsafe, gently guide them toward a trusted adult.'
        };
    }


    _userPrompt (rag, modelKey, input) {
        return {
            role : 'user',
            content : rag ?
                "Question: " + input + "\n\nContext:\n" + this.MODELS[modelKey].initialcontext :
                input
        };
    }


    _submitPrompt (requestid, modelid, contextwindow, modelKey, temperature, top_p, input, worker) {
        const rag = this.MODELS[modelKey].messages.length === 0 && this.MODELS[modelKey].initialcontext;

        if (this.MODELS[modelKey].messages.length === 0) {
            this.MODELS[modelKey].messages.push(this._systemPrompt(rag));
        }

        this.MODELS[modelKey].messages.push(this._userPrompt(rag, modelKey, input));

        const prompt = {
            messages : this.MODELS[modelKey].messages,
            temperature, top_p
        };
        console.log(prompt);

        this.MODELS[modelid + '-' + contextwindow].webllmEngine.chat.completions.create(prompt)
            .then((reply) => {
                console.log(reply);

                if (!this.MODELS[modelKey].busy) {
                    console.log('[mlforkids] response received after STOP');
                    return;
                }

                const response = reply.choices[0].message.content;
                this._replyToPrompt(requestid, modelid, contextwindow, response, worker);

                this.MODELS[modelKey].messages.push({
                    role : 'assistant', content : response
                });
                this.MODELS[modelKey].busy = false;
            })
            .catch((err) => {
                console.log('[mlforkids] language model fail', err);

                if (!this.MODELS[modelKey].busy) {
                    console.log('[mlforkids] error received after STOP');
                    return;
                }

                if (err.message.includes('tokens exceed context window size') && this.MODELS[modelKey].messages.length > 1 && !rag) {
                    this.MODELS[modelKey].messages.pop();
                    this.MODELS[modelKey].messages.splice(1, 1);
                    this._submitPrompt (requestid, modelid, contextwindow, modelKey, temperature, top_p, input, worker);
                }
                else {
                    this._replyToPrompt(requestid, modelid, contextwindow, 'Unable to respond', worker);
                    this.MODELS[modelKey].busy = false;
                }
            });
    }


    async _submitPromptWithTools (requestid, modelid, contextwindow, modelKey, temperature, top_p, input, targetid, worker) {
        const model = this.MODELS[modelKey];
        const runtime = this._runtime;

        const target = (runtime && targetid) ? runtime.getTargetById(targetid) : null;
        if (!target) {
            console.error('[mlforkids] prompt-with-tools needs the invoking sprite',
                { targetid, hasRuntime : !!runtime });
            this._replyToPrompt(requestid, modelid, contextwindow, 'Unable to respond', worker);
            model.busy = false;
            return;
        }

        const tools = toolRunner.listTools(target);
        if (tools.length === 0) {
            // no tools on this sprite - behave exactly like a plain prompt
            //  (this also avoids sending a tools parameter, which breaks
            //   models that cannot do function calling)
            return this._submitPrompt(requestid, modelid, contextwindow, modelKey,
                temperature, top_p, input, worker);
        }

        const toolsByName = {};
        tools.forEach((tool) => {
            toolsByName[tool.name] = tool;
        });
        const toolSchemas = tools.map((tool) => tool.schema);

        const rag = model.messages.length === 0 && model.initialcontext;
        if (model.messages.length === 0) {
            model.messages.push(this._systemPrompt(rag));
        }
        const userTurn = this._userPrompt(rag, modelKey, input);

        // tool exchanges are ephemeral: the loop works on a copy of the
        //  conversation, and only the user turn and the final answer are
        //  added to the history that future prompts will see
        //
        // web-llm does not allow a custom system message when tools are in
        //  use (it needs the system slot for its own function-calling
        //  prompt, and throws CustomSystemPromptError otherwise) - so in
        //  this working copy the child-safety prompt is downgraded to a
        //  user message; it stays as a system message in the stored
        //  conversation, which plain (tool-less) prompts continue to use
        const working = model.messages.map((msg) => (
            msg.role === 'system' ? { role : 'user', content : msg.content } : msg
        ));
        working.push(userTurn);

        const finish = (finalAnswer) => {
            this._replyToPrompt(requestid, modelid, contextwindow, finalAnswer, worker);
            model.messages.push(userTurn, { role : 'assistant', content : finalAnswer });
            model.busy = false;
        };

        try {
            for (let iteration = 0; iteration < MAX_TOOL_ITERATIONS; iteration++) {
                if (!model.busy) {
                    console.log('[mlforkids] tools prompt abandoned after STOP');
                    return;
                }

                const reply = await model.webllmEngine.chat.completions.create({
                    // copy - web-llm prepends its own tool system prompt to
                    //  the messages array it is given
                    messages : working.slice(),
                    tools : toolSchemas,
                    tool_choice : 'auto',
                    temperature, top_p
                });
                console.log(reply);

                if (!model.busy) {
                    console.log('[mlforkids] response received after STOP');
                    return;
                }

                const choice = reply.choices[0];
                const toolCalls = choice.message.tool_calls;

                if (choice.finish_reason !== 'tool_calls' || !toolCalls || toolCalls.length === 0) {
                    // the model answered with text instead of using a tool
                    return finish(choice.message.content || '');
                }

                // web-llm requires message content to be a string
                //  (null is valid in the OpenAI API, but rejected here)
                working.push(Object.assign({}, choice.message, { content : choice.message.content || '' }));

                const results = [];
                for (const toolCall of toolCalls) {
                    const requestedName = toolCall.function.name;
                    const tool = toolsByName[requestedName];
                    if (!tool) {
                        // teachable failure: name the model's mistake so the
                        //  student sees the consequence of their choices
                        return finish('The model tried to use a tool called "' + requestedName +
                            '", but there is no tool with that name.');
                    }

                    let toolArgs;
                    try {
                        toolArgs = JSON.parse(toolCall.function.arguments || '{}');
                    }
                    catch (err) {
                        return finish('The model tried to use the "' + tool.displayName +
                            '" tool, but did not describe the inputs in a way that could be understood.');
                    }

                    if (!model.busy) {
                        console.log('[mlforkids] tools prompt abandoned after STOP');
                        return;
                    }

                    const outcome = await toolRunner.runToolScript(
                        runtime, target, tool, toolArgs,
                        () => !model.busy);
                    if (outcome.aborted || !model.busy) {
                        console.log('[mlforkids] tool run abandoned after STOP');
                        return;
                    }

                    // a tool that finishes without returning an answer is a
                    //  normal case (e.g. a tool that just moves the sprite)
                    const resultText = (typeof outcome.answer === 'undefined' ||
                                        outcome.answer === null ||
                                        outcome.answer === '') ?
                        'The ' + tool.displayName + ' tool completed successfully' :
                        String(outcome.answer);

                    working.push({
                        role : 'tool',
                        tool_call_id : toolCall.id,
                        content : resultText
                    });
                    results.push(resultText);
                }

                // every tool call in this round ran - the tool results are the
                //  answer (function-calling models essentially never produce a
                //  "stop" response while tools are present, so there is no
                //  point asking the model to wrap up)
                return finish(results.join('\n'));
            }

            finish('The model used its tools many times but did not give an answer');
        }
        catch (err) {
            console.log('[mlforkids] language model fail', err);

            if (!model.busy) {
                console.log('[mlforkids] error received after STOP');
                return;
            }
            this._replyToPrompt(requestid, modelid, contextwindow, 'Unable to respond', worker);
            model.busy = false;
        }
    }


    _enableToolsSupportForModel (webllmLib, modelid) {
        // the tools support in the palette is hidden until a model capable of
        //  function calling is in use - this is checked as soon as the web-llm
        //  library is loaded (rather than after the slow model download) so
        //  students can start making tools while they wait, and there is no
        //  hide event: once revealed, tools support stays revealed
        if (!this._runtime) {
            return;
        }
        const supported = webllmLib &&
            Array.isArray(webllmLib.functionCallingModelIds) &&
            webllmLib.functionCallingModelIds.indexOf(modelid) !== -1;
        if (supported) {
            console.log('[mlforkids] model supports function calling - enabling tools support');
            this._runtime.emit(TOOLS_SUPPORT_AVAILABLE_EVENT);

            // loading a new project resets the runtime's tools-enabled flag
            //  (runtime.dispose), but extensions stay loaded - re-request
            //  tools support so the palette stays available
            //  (registered once - one listener covers all models)
            if (!this._projectLoadListenerRegistered) {
                this._projectLoadListenerRegistered = true;
                this._runtime.on('PROJECT_LOADED', () => {
                    this._runtime.emit(TOOLS_SUPPORT_AVAILABLE_EVENT);
                });
            }
        }
    }


    _loadWebLlmProjectSupport () {
        console.log('[mlforkids] loading web-llm script');
        return new Promise((resolve, reject) => {
            if (window.mlforkidsWebLlm) {
                return resolve(window.mlforkidsWebLlm);
            }

            const scriptObj = document.createElement('script');
            scriptObj.src = './mlforkids-thirdparty-libs/web-llm/index.js';
            scriptObj.onload = () => {
                this._waitForWebLlmModule(resolve);
                scriptObj.remove();
            };
            scriptObj.onerror = (err) => {
                this.state = 'ERROR';
                console.log('[mlforkids] Failed to load web-llm module', err);
                reject();
            };
            document.head.appendChild(scriptObj);
        });
    }

    _waitForWebLlmModule (resolve) {
        if (window.mlforkidsWebLlm) {
            console.log('[mlforkids] loaded web-llm');
            resolve(window.mlforkidsWebLlm);
        }
        else {
            setTimeout(() => {
                this._waitForWebLlmModule(resolve);
            }, 3000);
        }
    }
}

module.exports = ML4KidsWebLlm;
