const log = require('../util/log');

/**
 * Recycle bin for empty stackFrame objects
 * @type Array<_StackFrame>
 */
const _stackFrameFreeList = [];

/**
 * A frame used for each level of the stack. A general purpose
 * place to store a bunch of execution context and parameters
 * @param {boolean} warpMode Whether this level of the stack is warping
 * @class
 * @private
 */
class _StackFrame {
    constructor (warpMode) {
        /**
         * Whether this level of the stack is a loop.
         * @type {boolean}
         */
        this.isLoop = false;

        /**
         * Whether this level is in warp mode.  Is set by some legacy blocks and
         * "turbo mode"
         * @type {boolean}
         */
        this.warpMode = warpMode;

        /**
         * Reported value from just executed block.
         * @type {Any}
         */
        this.justReported = null;

        /**
         * The active block that is waiting on a promise.
         * @type {string}
         */
        this.reporting = '';

        /**
         * Persists reported inputs during async block.
         * @type {object}
         */
        this.reported = null;

        /**
         * Name of waiting reporter.
         * @type {string}
         */
        this.waitingReporter = null;

        /**
         * Procedure parameters.
         * @type {object}
         */
        this.params = null;

        /**
         * A context passed to block implementations.
         * @type {object}
         */
        this.executionContext = null;

        /**
         * On the caller's frame for a reporter-shaped tool call (the frame
         * active just before Sequencer.ml4kStepToTool pushed the tool's
         * definition frame), the resolve function for the Promise that call
         * is waiting on. Stored here -- rather than on the definition frame
         * itself -- because sequential statements within the tool's body
         * reuse and reset that frame (Thread.reuseStackForNextBlock) as
         * execution advances from one to the next, which would otherwise
         * wipe it out before mlforkidstools_report ever ran. Called by the
         * mlforkidstools_report primitive with the reported value, or with a default
         * value if this frame is released (see Thread.popStack) before a
         * report is reached.
         * @type {?Function}
         */
        this.ml4kReportResolve = null;

        /**
         * Alongside ml4kReportResolve, the thread.stackFrames.length to pop back
         * down to once the pending report resolves, i.e. this frame's own
         * depth plus one (the depth right after Sequencer.ml4kStepToTool pushed
         * the definition frame). The tool's body may be arbitrarily deeper
         * than that by the time it reports (nested control-flow blocks push
         * their own frames), so resolving needs to know how far to unwind in
         * one go rather than one level at a time.
         * @type {?number}
         */
        this.ml4kReportReturnDepth = null;

        /**
         * Alongside ml4kReportResolve, the tool code this frame is waiting on a
         * report from. Used by ml4kIsToolRecursiveCall to detect a tool calling
         * itself (directly or through an intermediate report-tool), since a
         * reporter-shaped call never gets pushed onto thread.stack as a
         * mlforkidstools_call entry the way a statement call does.
         * @type {?string}
         */
        this.ml4kReportToolCode = null;
    }

    /**
     * Reset all properties of the frame to pristine null and false states.
     * Used to recycle.
     * @returns {_StackFrame} this
     */
    reset () {

        this.isLoop = false;
        this.warpMode = false;
        this.justReported = null;
        this.reported = null;
        this.waitingReporter = null;
        this.params = null;
        this.executionContext = null;
        this.ml4kReportResolve = null;
        this.ml4kReportReturnDepth = null;
        this.ml4kReportToolCode = null;

        return this;
    }

    /**
     * Reuse an active stack frame in the stack.
     * @param {?boolean} warpMode defaults to current warpMode
     * @returns {_StackFrame} this
     */
    reuse (warpMode = this.warpMode) {
        this.reset();
        this.warpMode = Boolean(warpMode);
        return this;
    }

    /**
     * Create or recycle a stack frame object.
     * @param {boolean} warpMode Enable warpMode on this frame.
     * @returns {_StackFrame} The clean stack frame with correct warpMode setting.
     */
    static create (warpMode) {
        const stackFrame = _stackFrameFreeList.pop();
        if (typeof stackFrame !== 'undefined') {
            stackFrame.warpMode = Boolean(warpMode);
            return stackFrame;
        }
        return new _StackFrame(warpMode);
    }

    /**
     * Put a stack frame object into the recycle bin for reuse.
     * @param {_StackFrame} stackFrame The frame to reset and recycle.
     */
    static release (stackFrame) {
        if (typeof stackFrame !== 'undefined') {
            _stackFrameFreeList.push(stackFrame.reset());
        }
    }
}

/**
 * A thread is a running stack context and all the metadata needed.
 * @param {?string} firstBlock First block to execute in the thread.
 * @class
 */
class Thread {
    constructor (firstBlock) {
        /**
         * ID of top block of the thread
         * @type {!string}
         */
        this.topBlock = firstBlock;

        /**
         * Stack for the thread. When the sequencer enters a control structure,
         * the block is pushed onto the stack so we know where to exit.
         * @type {Array.<string>}
         */
        this.stack = [];

        /**
         * Stack frames for the thread. Store metadata for the executing blocks.
         * @type {Array.<_StackFrame>}
         */
        this.stackFrames = [];

        /**
         * Status of the thread, one of three states (below)
         * @type {number}
         */
        this.status = 0; /* Thread.STATUS_RUNNING */

        /**
         * Whether the thread is killed in the middle of execution.
         * @type {boolean}
         */
        this.isKilled = false;

        /**
         * Target of this thread.
         * @type {?Target}
         */
        this.target = null;

        /**
         * The Blocks this thread will execute.
         * @type {Blocks}
         */
        this.blockContainer = null;

        /**
         * Whether the thread requests its script to glow during this frame.
         * @type {boolean}
         */
        this.requestScriptGlowInFrame = false;

        /**
         * Which block ID should glow during this frame, if any.
         * @type {?string}
         */
        this.blockGlowInFrame = null;

        /**
         * A timer for when the thread enters warp mode.
         * Substitutes the sequencer's count toward WORK_TIME on a per-thread basis.
         * @type {?Timer}
         */
        this.warpTimer = null;

        this.justReported = null;

        /**
         * Number of tool calls on this thread currently waiting on a report
         * value (see mlforkidstools_report). Bookkeeping only -- incremented by
         * BlockUtility.ml4kStartToolReport and decremented wherever a pending
         * report resolves (BlockUtility.ml4kReportToolValue, or the fallthrough
         * default in Thread.popStack) -- not read by the sequencer itself.
         * @type {number}
         */
        this.ml4kReportWaitDepth = 0;

        /**
         * Set by BlockUtility.ml4kStartToolReport immediately after creating the
         * Promise a reporter-shaped tool call returns, and consumed by
         * Sequencer.stepThread on its very next status check. A tool's body
         * runs on this same thread (pushed via Sequencer.ml4kStepToTool), so
         * genuinely yielding for that promise like any other promise-
         * returning primitive would permanently exclude this thread from
         * stepping before its own body -- containing the only report that
         * could resolve the promise -- ever ran. See Sequencer.stepThread.
         * @type {boolean}
         */
        this.ml4kReportJustStarted = false;
    }

    /**
     * Thread status for initialized or running thread.
     * This is the default state for a thread - execution should run normally,
     * stepping from block to block.
     * @constant
     */
    static get STATUS_RUNNING () {
        return 0;
    }

    /**
     * Threads are in this state when a primitive is waiting on a promise;
     * execution is paused until the promise changes thread status.
     * @constant
     */
    static get STATUS_PROMISE_WAIT () {
        return 1;
    }

    /**
     * Thread status for yield.
     * @constant
     */
    static get STATUS_YIELD () {
        return 2;
    }

    /**
     * Thread status for a single-tick yield. This will be cleared when the
     * thread is resumed.
     * @constant
     */
    static get STATUS_YIELD_TICK () {
        return 3;
    }

    /**
     * Thread status for a finished/done thread.
     * Thread is in this state when there are no more blocks to execute.
     * @constant
     */
    static get STATUS_DONE () {
        return 4;
    }

    /**
     * Push stack and update stack frames appropriately.
     * @param {string} blockId Block ID to push to stack.
     */
    pushStack (blockId) {
        this.stack.push(blockId);
        // Push an empty stack frame, if we need one.
        // Might not, if we just popped the stack.
        if (this.stack.length > this.stackFrames.length) {
            const parent = this.stackFrames[this.stackFrames.length - 1];
            this.stackFrames.push(_StackFrame.create(typeof parent !== 'undefined' && parent.warpMode));
        }
    }

    /**
     * Reset the stack frame for use by the next block.
     * (avoids popping and re-pushing a new stack frame - keeps the warpmode the same
     * @param {string} blockId Block ID to push to stack.
     */
    reuseStackForNextBlock (blockId) {
        this.stack[this.stack.length - 1] = blockId;
        this.stackFrames[this.stackFrames.length - 1].reuse();
    }

    /**
     * Pop last block on the stack and its stack frame.
     * @returns {string} Block ID popped from the stack.
     */
    popStack () {
        _StackFrame.release(this.stackFrames.pop());
        const poppedBlockId = this.stack.pop();
        // If this pop just unwound the stack exactly back down to a caller
        // frame still waiting on a mlforkidstools_report -- i.e. its own
        // ml4kReportReturnDepth, recorded when it made the call -- the tool's
        // body ended (by falling off the end, or via stopThisScript) without
        // ever reporting a value. Resolve the pending promise with a
        // default so the caller doesn't hang forever. This single hook
        // covers every way a report-tool's body can end, with no
        // special-casing needed at each of those call sites. Checking the
        // newly uncovered top frame here (rather than the frame just
        // released) is what makes this work even though a report-tool's
        // body may be several frames deeper than its caller by the time it
        // ends (nested control-flow blocks push their own frames).
        const newTop = this.stackFrames[this.stackFrames.length - 1];
        if (newTop && newTop.ml4kReportResolve && newTop.ml4kReportReturnDepth === this.stackFrames.length) {
            log.warn('Tool finished without reporting a value; defaulting to 0.');
            // mlforkids: lets the ML4K tool-runner (which supplies its own
            // ml4kReportResolve for model-invoked tools) distinguish this
            // fell-through default from a genuinely reported 0
            this.ml4kReportFellThrough = true;
            const resolve = newTop.ml4kReportResolve;
            newTop.ml4kReportResolve = null;
            newTop.ml4kReportReturnDepth = null;
            newTop.ml4kReportToolCode = null;
            this.ml4kReportWaitDepth--;
            resolve(0);
            // See the matching comment in BlockUtility.ml4kReportToolValue:
            // resolving only schedules the caller's `.then()` as a
            // microtask, so mark the thread waiting again to keep the
            // sequencer from re-executing the caller's frame, just
            // uncovered above, before that microtask has run.
            this.status = Thread.STATUS_PROMISE_WAIT;
        }
        return poppedBlockId;
    }

    /**
     * Pop back down the stack frame until we hit a procedure call or the stack frame is emptied
     */
    stopThisScript () {
        let blockID = this.peekStack();
        while (blockID !== null) {
            const block = this.target.blocks.getBlock(blockID);
            if (typeof block !== 'undefined' &&
                (block.opcode === 'procedures_call' || block.opcode === 'mlforkidstools_call')) {
                break;
            }
            this.popStack();
            blockID = this.peekStack();
        }

        if (this.stack.length === 0) {
            // Clean up!
            this.requestScriptGlowInFrame = false;
            this.status = Thread.STATUS_DONE;
        }
    }

    /**
     * Get top stack item.
     * @returns {?string} Block ID on top of stack.
     */
    peekStack () {
        return this.stack.length > 0 ? this.stack[this.stack.length - 1] : null;
    }


    /**
     * Get top stack frame.
     * @returns {?object} Last stack frame stored on this thread.
     */
    peekStackFrame () {
        return this.stackFrames.length > 0 ? this.stackFrames[this.stackFrames.length - 1] : null;
    }

    /**
     * Get stack frame above the current top.
     * @returns {?object} Second to last stack frame stored on this thread.
     */
    peekParentStackFrame () {
        return this.stackFrames.length > 1 ? this.stackFrames[this.stackFrames.length - 2] : null;
    }

    /**
     * Push a reported value to the parent of the current stack frame.
     * @param {*} value Reported value to push.
     */
    pushReportedValue (value) {
        this.justReported = typeof value === 'undefined' ? null : value;
    }

    /**
     * Initialize procedure parameters on this stack frame.
     */
    initParams () {
        const stackFrame = this.peekStackFrame();
        if (stackFrame.params === null) {
            stackFrame.params = {};
        }
    }

    /**
     * Add a parameter to the stack frame.
     * Use when calling a procedure with parameter values.
     * @param {!string} paramName Name of parameter.
     * @param {*} value Value to set for parameter.
     */
    pushParam (paramName, value) {
        const stackFrame = this.peekStackFrame();
        stackFrame.params[paramName] = value;
    }

    /**
     * Get a parameter at the lowest possible level of the stack.
     * @param {!string} paramName Name of parameter.
     * @returns {*} value Value for parameter.
     */
    getParam (paramName) {
        for (let i = this.stackFrames.length - 1; i >= 0; i--) {
            const frame = this.stackFrames[i];
            if (frame.params === null) {
                continue;
            }
            if (Object.prototype.hasOwnProperty.call(frame.params, paramName)) {
                return frame.params[paramName];
            }
            return null;
        }
        return null;
    }

    /**
     * Whether the current execution of a thread is at the top of the stack.
     * @returns {boolean} True if execution is at top of the stack.
     */
    atStackTop () {
        return this.peekStack() === this.topBlock;
    }


    /**
     * Switch the thread to the next block at the current level of the stack.
     * For example, this is used in a standard sequence of blocks,
     * where execution proceeds from one block to the next.
     */
    goToNextBlock () {
        const nextBlockId = this.target.blocks.getNextBlock(this.peekStack());
        this.reuseStackForNextBlock(nextBlockId);
    }

    /**
     * Attempt to determine whether a procedure call is recursive,
     * by examining the stack.
     * @param {!string} procedureCode Procedure code of procedure being called.
     * @returns {boolean} True if the call appears recursive.
     */
    isRecursiveCall (procedureCode) {
        let callCount = 5; // Max number of enclosing procedure calls to examine.
        const sp = this.stack.length - 1;
        for (let i = sp - 1; i >= 0; i--) {
            const block = this.target.blocks.getBlock(this.stack[i]);
            // mlforkids: threads started by the ML4K tool-runner have a null
            // bottom stack entry (it holds the model-supplied params), for
            // which getBlock returns undefined
            if (block && block.opcode === 'procedures_call' &&
                block.mutation.proccode === procedureCode) {
                return true;
            }
            if (--callCount < 0) return false;
        }
        return false;
    }

    /**
     * Attempt to determine whether a tool call is recursive,
     * by examining the stack.
     * @param {!string} toolCode Tool code of tool being called.
     * @returns {boolean} True if the call appears recursive.
     */
    ml4kIsToolRecursiveCall (toolCode) {
        let callCount = 5; // Max number of enclosing tool calls to examine.
        const sp = this.stack.length - 1;
        for (let i = sp - 1; i >= 0; i--) {
            const blockId = this.stack[i];
            const block = this.target.blocks.getBlock(blockId);
            // mlforkids: threads started by the ML4K tool-runner have a null
            // bottom stack entry (it holds the model-supplied params), for
            // which getBlock returns undefined
            if (block && block.opcode === 'mlforkidstools_call' && block.mutation.toolcode === toolCode) {
                return true;
            }
            // A reporter-shaped tool call (one whose tool contains a
            // mlforkidstools_report) is never pushed onto the stack as a mlforkidstools_call
            // entry -- it's flattened into the caller's block-input ops and
            // invoked as a plain synchronous call (see execute.js). Its
            // caller frame is marked with the tool code it's waiting on a
            // report from though (see BlockUtility.ml4kStartToolReport), so
            // check that directly instead of the stack's block IDs, which
            // only reflect whatever's currently executing at each level.
            if (this.stackFrames[i].ml4kReportToolCode === toolCode) {
                return true;
            }
            if (--callCount < 0) return false;
        }
        return false;
    }
}

module.exports = Thread;
